import { describe, it, expect } from "vitest";

describe("MHPCO Claim Office", () => {
  describe("Quote Premium", () => {
    it.todo("should compute base premium for a single sword with first-insurance surcharge and processing fee");
    it.todo("should compute base premium for each item type (amulet, staff, potion)");
    it.todo("should add 50% surcharge for a cursed item");
    it.todo("should add 30% surcharge for highly enchanted item (enchantment >= 5)");
    it.todo("should apply 20% loyalty discount for long-standing customer (>= 2 years)");
    it.todo("should apply 15% discount on subsequent contracts after the first");
    it.todo("should sum premiums for multiple items in a single quote");
    it.todo("should compute component premium at 25G each and 60G for a block of 3 alike");
    it.todo("should round amounts in MHPCO's favor (ceiling for premiums)");
  });

  describe("Process Claims", () => {
    it.todo("should apply 100G deductible to a basic damage claim");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse damage to high-enchantment items (>= 8) at 50%");
    it.todo("should fully reimburse damage to dragon material items");
  });

  describe("CLI Integration", () => {
    it.todo("should read JSON from stdin and write results JSON to stdout");
  });
});

