import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote Premium", () => {
    it("should compute base premium for a single sword with first-insurance surcharge and processing fee", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      });
      // sword base premium: 100G
      // first insurance surcharge: +10% → 110G
      // processing fee: +5G → 115G
      expect(result.results[0].premium).toBe(115);
    });
    it("should compute base premium for each item type (amulet, staff, potion)", () => {
      const quoteAmulet = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "amulet", material: "silver", enchantment: 2, cursed: false },
            ],
          },
        ],
      });
      // amulet base premium: 60G
      // first insurance surcharge: +10% → 66G
      // processing fee: +5G → 71G
      expect(quoteAmulet.results[0].premium).toBe(71);

      const quoteStaff = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "staff", material: "oak", enchantment: 1, cursed: false },
            ],
          },
        ],
      });
      // staff base premium: 80G
      // first insurance surcharge: +10% → 88G
      // processing fee: +5G → 93G
      expect(quoteStaff.results[0].premium).toBe(93);

      const quotePotion = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // potion base premium: 40G
      // first insurance surcharge: +10% → 44G
      // processing fee: +5G → 49G
      expect(quotePotion.results[0].premium).toBe(49);
    });
    it.todo("should add 50% surcharge for a cursed item");
    it.todo("should add 30% surcharge for highly enchanted item (enchantment >= 5)");
    it.todo("should apply 20% loyalty discount for long-standing customer (>= 2 years)");
    it.todo("should apply 15% discount on subsequent contracts after the first");
    it.todo("should sum premiums for multiple items in a single quote");
    it.todo("should compute component premium at 25G each and 60G for a block of 3 alike");
    it.todo("should round amounts in MHPCO's favor (ceiling for premiums)");
  });

  describe("Process Claims", () => {
    it.todo("should apply 100G deductible to a basic damage claim");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse damage to high-enchantment items (>= 8) at 50%");
    it.todo("should fully reimburse damage to dragon material items");
  });

  describe("CLI Integration", () => {
    it.todo("should read JSON from stdin and write results JSON to stdout");
  });
});

